import { useLocation } from "react-router-dom";
import { useState, useEffect } from "react";
import "./styles/Books.css";

function LibrarianBooks() {
  // ✅ ALL HOOKS AT TOP
  const location = useLocation();
  const [genre, setGenre] = useState("");
  const [books, setBooks] = useState([]);

  // ✅ SET GENRE SAFELY
  useEffect(() => {
    const g =
      location.state?.genre || localStorage.getItem("librarianGenre");

    if (g) {
      setGenre(g);
      localStorage.setItem("librarianGenre", g);
    }
  }, [location.state]);

  // ✅ LOAD BOOKS WHEN GENRE CHANGES
  useEffect(() => {
    if (!genre) return;

    const demoBooks = [
      {
        title: `${genre} Book 1`,
        author: "Author One",
        cover: "https://via.placeholder.com/200x280",
        status: "Available",
      },
      {
        title: `${genre} Book 2`,
        author: "Author Two",
        cover: "https://via.placeholder.com/200x280",
        status: "Not Available",
      },
    ];

    setBooks(demoBooks);
  }, [genre]);

  // 🔁 TOGGLE STATUS
  const toggleStatus = (index) => {
    setBooks((prev) =>
      prev.map((book, i) =>
        i === index
          ? {
              ...book,
              status:
                book.status === "Available"
                  ? "Not Available"
                  : "Available",
            }
          : book
      )
    );
  };

  // ❌ REMOVE BOOK
  const removeBook = (index) => {
    setBooks((prev) => prev.filter((_, i) => i !== index));
  };

  // ✅ SAFE RENDER (NO EARLY RETURN BEFORE HOOKS)
  if (!genre) {
    return <h2 style={{ padding: "40px" }}>Genre not found</h2>;
  }

  return (
    <div className="books-page">
      <h1 className="books-title">Manage {genre} Books</h1>

      <div className="books-grid">
        {books.map((book, i) => (
          <div key={i} className="book-card">
            <img src={book.cover} alt={book.title} />

            <h3>{book.title}</h3>
            <p>{book.author}</p>

            <span
              className={`card-status ${
                book.status === "Available" ? "avail" : "not-avail"
              }`}
            >
              {book.status}
            </span>

            <div
              style={{
                marginTop: "14px",
                display: "flex",
                gap: "10px",
                justifyContent: "center",
              }}
            >
              <button
                className="borrow-btn"
                onClick={() => toggleStatus(i)}
              >
                🔁 Toggle Status
              </button>

              <button
                className="return-btn"
                onClick={() => removeBook(i)}
              >
                ❌ Remove
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default LibrarianBooks;
